# find the 'بِبَيْعِكُمُ' segment up to before the next bracket '﴾' after it
start = raw.find('بِبَيْعِكُمُ')
extra_spans = []
if start != -1:
    end = raw.find('﴾', start)
    if end != -1:
        span_text = raw[start:end]
        extra_spans.append((start, start+len(span_text), span_text, 'Aya'))
start, extra_spans[:1]

# Deduplicate
uniq = {}
for s in spans + extra_spans:
    uniq[(s[0],s[1],s[3])] = s
uniq_list = sorted(uniq.values(), key=lambda x: x[0])
len(uniq_list), uniq_list
